// Utility function: get display name from category slug
function getCategoryName(categorySlug) {
    let fullName = categorySlug.charAt(0).toUpperCase() + categorySlug.slice(1);
    
    if (siteConfig.categoryData && siteConfig.categoryData.length > 0) {
        for (const cat of siteConfig.categoryData) {
            if (cat.category_slug === categorySlug || cat.slug === categorySlug) {
                fullName = cat.category_name || cat.name || categorySlug;
                break;
            }
        }
    }

    // Aggressive shortening for header nav to keep it in one line
    const replacements = {
        'Small Equipment': 'Sm. Eq.',
        'Jump Rope': 'JR',
        'Kettlebell': 'KB',
        'Yoga Ball': 'YB',
        'Resistance Band': 'RB',
        'Resistance Bands': 'RB',
        'No Equipment': 'No Eq.',
        'Training': 'Tr.',
        'Exercises': 'Ex.',
        'Improvement': 'Imp.',
        'Correction': 'Corr.',
        'Beginner': 'Beg.',
        'Advanced': 'Adv.',
        'Tutorials': 'Tut.',
        'Techniques': 'Tech.',
        'Workout': 'Work.',
        'Routine': 'Rout.',
        'Guide': 'Gd.',
        'History': 'Hist.',
        'Trending': 'Trnd.',
        'Equipment': 'Eq.',
        'Exercise': 'Ex.',
        'Begginer': 'Beg.',
        'Yoga': 'Yo.',
        'Pilates': 'Pi.',
        'Fitness': 'Fit.',
        'Health': 'Hlth.',
        'Nutrition': 'Nutr.',
        'Meditation': 'Med.',
        'Breathing': 'Brth.',
        'Practice': 'Prac.',
        'Weight': 'Wt.',
        'Strength': 'Str.',
        'Cardio': 'Car.',
        'Muscle': 'Mus.',
        'Central': 'Ctr.',
        'Protein': 'Prot.',
        'Breakfast': 'Brkf.',
        'Lunch': 'Lnch.',
        'Dinner': 'Dinn.',
        'Healthy': 'Hlth.',
        'Choice': 'Ch.',
        'Combo': 'Cmb.',
        'Design': 'Dsg.',
        'Follow Along': 'FA',
        'Enough': 'En.',
        'Getting': 'Gett.',
        'Practice': 'Prac.',
        'Workout': 'Wkt.',
        'Equipment': 'Eqp.',
        'Nutritious': 'Nutr.'
    };

    let shortName = fullName;
    for (const [old, newVal] of Object.entries(replacements)) {
        shortName = shortName.replace(old, newVal);
    }
    return shortName;
}

class DataService {
    constructor() {
        this.articleIndex = {
            articles: siteConfig.articles,
            categories: siteConfig.categories
        };
        this.categoryIndex = {};
        this.articleCache = {};
        
        // Initialize category index
        siteConfig.categories.forEach(cat => {
            this.categoryIndex[cat] = siteConfig.articles.filter(a => a.category === cat);
        });
    }

    async loadArticleIndex() {
        return this.articleIndex;
    }

    async loadCategoryIndex() {
        return this.categoryIndex;
    }

    async loadArticleById(id) {
        if (this.articleCache[id]) {
            return this.articleCache[id];
        }
        try {
            // Basic data is embedded, but full content may still need loading
            // For simplicity, we assume articles have full content or try fetch
            const article = siteConfig.articles.find(a => a.id === id);
            if (article && article.content) {
                return article;
            }
            
            const response = await fetch(`data/article-${id}.json`);
            if (!response.ok) throw new Error(`Failed to load article ${id}`);
            const fullArticle = await response.json();
            this.articleCache[id] = fullArticle;
            return fullArticle;
        } catch (error) {
            console.error('Error loading article:', error);
            return null;
        }
    }

    async loadArticleBySlug(slug) {
        const article = siteConfig.articles.find(a => a.slug === slug);
        if (article) {
            return await this.loadArticleById(article.id);
        }
        return null;
    }

    async getArticlesByCategory(category) {
        return this.categoryIndex[category] || [];
    }
}

class App {
    constructor() {
        this.dataService = new DataService();
        this.itemsPerPage = 15;
        this.currentPage = 1;
        this.init();
    }

    init() {
        window.addEventListener('hashchange', () => this.handleRoute());
        this.handleRoute();
        // Load sidebar content
        this.renderSidebarCategories();
        this.loadRecommendedNews();
        this.loadCategorySpecificWidgets();
        // Update footer links
        this.updateFooterLinks();
        // Initialize ad features
        this.initFloatingAds();
        // Initialize mobile menu
        this.initMobileMenu();
        // Initialize search
        this.initSearch();
    }
    
    initSearch() {
        const searchContainer = document.getElementById('search-container');
        const searchToggleBtn = document.getElementById('search-toggle-btn');
        const searchForm = document.getElementById('search-form');
        const searchInput = document.getElementById('search-input');
        
        if (searchToggleBtn && searchContainer && searchInput) {
            searchToggleBtn.onclick = (e) => {
                e.preventDefault();
                e.stopPropagation();
                searchContainer.classList.toggle('active');
                if (searchContainer.classList.contains('active')) {
                    searchInput.focus();
                }
            };

            // Close search when clicking outside
            document.addEventListener('click', (e) => {
                if (!searchContainer.contains(e.target)) {
                    searchContainer.classList.remove('active');
                }
            });
        }

        if (searchForm && searchInput) {
            searchForm.onsubmit = (e) => {
                e.preventDefault();
                const query = searchInput.value.trim();
                if (query) {
                    window.location.hash = `#/search/${encodeURIComponent(query)}`;
                    if (searchContainer) searchContainer.classList.remove('active');
                }
            };
        }
    }
    
    initMobileMenu() {
        const toggle = document.getElementById('mobile-menu-toggle');
        const nav = document.getElementById('main-nav');
        if (toggle && nav) {
            toggle.onclick = (e) => {
                e.preventDefault();
                e.stopPropagation();
                nav.classList.toggle('active');
                toggle.classList.toggle('active');
            };
            
            // Close menu when clicking outside
            document.addEventListener('click', (e) => {
                if (!toggle.contains(e.target) && !nav.contains(e.target)) {
                    nav.classList.remove('active');
                    toggle.classList.remove('active');
                }
            });
            
            // Close menu when clicking a link inside nav
            nav.addEventListener('click', (e) => {
                if (e.target.tagName === 'A') {
                    nav.classList.remove('active');
                    toggle.classList.remove('active');
                }
            });
        }
    }
    
    initFloatingAds() {
        const floatingAds = document.querySelectorAll('.floating-ad');
        floatingAds.forEach(ad => {
            // Add close button
            const closeBtn = document.createElement('div');
            closeBtn.className = 'close-ad-btn';
            closeBtn.innerHTML = '×';
            closeBtn.onclick = (e) => {
                e.stopPropagation();
                ad.style.display = 'none';
            };
            ad.appendChild(closeBtn);
            
            // Add countdown timer
            const countdownEl = document.createElement('div');
            countdownEl.className = 'ad-countdown';
            ad.appendChild(countdownEl);
            
            let timeLeft = 15;
            const updateCountdown = () => {
                countdownEl.innerHTML = `Auto-close in ${timeLeft}s`;
                if (timeLeft <= 0) {
                    ad.style.opacity = '0';
                    setTimeout(() => ad.style.display = 'none', 500);
                    clearInterval(timer);
                }
                timeLeft -= 1;
            };
            
            updateCountdown();
            const timer = setInterval(updateCountdown, 1000);
        });
    }

    async loadCategorySpecificWidgets() {
        const articleIndex = await this.dataService.loadArticleIndex();
        if (!articleIndex || !siteConfig.categories) return;
        
        const container = document.getElementById('sidebar-category-widgets');
        if (!container) return;

        // Pick 2 random categories
        const shuffledCats = [...siteConfig.categories].sort(() => Math.random() - 0.5);
        const selectedCats = shuffledCats.slice(0, 2);
        
        let html = '';
        for (const cat of selectedCats) {
            const catArticles = articleIndex.articles
                .filter(a => a.category === cat)
                .sort(() => Math.random() - 0.5)
                .slice(0, 3);
            
            if (catArticles.length > 0) {
                html += `
                    <div class="sidebar-widget">
                        <h3>Trending in ${getCategoryName(cat)}</h3>
                        <div class="sidebar-news-list">
                            ${catArticles.map(a => `
                                <div class="sidebar-news-item">
                                    <a href="article.html#/article/${a.slug}">${a.title}</a>
                                </div>
                            `).join('')}
                        </div>
                    </div>
                `;
            }
        }
        container.innerHTML = html;
    }
    
    renderSidebarCategories() {
        const container = document.getElementById('sidebar-categories');
        if (!container || !siteConfig.categories) return;
        
        let html = '<ul style="list-style: none; padding: 0;">';
        for (const cat of siteConfig.categories) {
            html += `
                <li style="margin-bottom: 0.5rem; border-bottom: 1px solid var(--gray-50); padding-bottom: 0.5rem;">
                    <a href="index.html#/category/${cat}" style="color: var(--text-color); display: block;">
                        ${getCategoryName(cat)}
                    </a>
                </li>
            `;
        }
        html += '</ul>';
        container.innerHTML = html;
    }
    
    updateFooterLinks() {
        // Categories in footer
        const catContainer = document.getElementById('footer-categories-container');
        if (catContainer && siteConfig.categories) {
            catContainer.innerHTML = siteConfig.categories
                .slice(0, 6)
                .map(cat => `<a href="index.html#/category/${cat}">${getCategoryName(cat)}</a>`)
                .join('');
        }

        // Back to top functionality
        const backToTopBtn = document.getElementById('back-to-top');
        if (backToTopBtn) {
            window.addEventListener('scroll', () => {
                if (window.pageYOffset > 500) {
                    backToTopBtn.style.opacity = '1';
                    backToTopBtn.style.visibility = 'visible';
                } else {
                    backToTopBtn.style.opacity = '0';
                    backToTopBtn.style.visibility = 'hidden';
                }
            });

            backToTopBtn.addEventListener('click', () => {
                window.scrollTo({
                    top: 0,
                    behavior: 'smooth'
                });
            });
        }

        // Newsletter form
        const newsletterForm = document.querySelector('.footer-newsletter');
        if (newsletterForm) {
            newsletterForm.addEventListener('submit', (e) => {
                e.preventDefault();
                const input = newsletterForm.querySelector('input');
                const button = newsletterForm.querySelector('button');
                const originalText = button.textContent;
                
                button.textContent = 'Joined!';
                button.disabled = true;
                input.value = '';
                input.disabled = true;
                
                setTimeout(() => {
                    button.textContent = originalText;
                    button.disabled = false;
                    input.disabled = false;
                }, 3000);
            });
        }
    }

    async loadRecommendedNews() {
        const articleIndex = await this.dataService.loadArticleIndex();
        if (!articleIndex) return;
        
        // Select 5 random articles as recommended news
        const shuffled = [...articleIndex.articles].sort(() => Math.random() - 0.5);
        const recommended = shuffled.slice(0, 5);
        
        // Render to sidebar
        this.renderRecommendedNews(recommended);
    }
    
    renderRecommendedNews(newsList) {
        const container = document.getElementById('sidebar-recommended-news');
        if (!container) return;
        
        let html = '';
        for (const news of newsList) {
            html += `
                <div class="sidebar-news-item">
                    <a href="article.html#/article/${news.slug}">${news.title}</a>
                </div>
            `;
        }
        
        container.innerHTML = html;
    }

    handleRoute() {
        const isArticlePage = window.location.pathname.includes('article.html');
        let hash = window.location.hash.slice(1) || '/';
        if (hash.startsWith('/')) {
            hash = hash.slice(1);
        }
        const parts = hash.split('/');
        const route = parts[0];

        if (route === 'article' && parts[1]) {
            this.renderArticle(parts[1]);
        } else if (route === 'search' && parts[1]) {
            this.renderSearch(decodeURIComponent(parts[1]));
        } else if (isArticlePage) {
            // If on article page but no article slug, go back to home
            window.location.href = 'index.html#/';
        } else if (route === '' || route === 'page') {
            this.currentPage = route === 'page' ? parseInt(parts[1]) || 1 : 1;
            this.renderHome();
        } else if (route === 'category' && parts[1]) {
            this.currentPage = parts[2] ? parseInt(parts[2]) || 1 : 1;
            this.renderCategory(parts[1]);
        } else {
            this.currentPage = 1;
            this.renderHome();
        }
        
        // Scroll to top on every route change
        window.scrollTo(0, 0);
    }

    showLoading() {
        const app = document.getElementById('app');
        app.innerHTML = '<div class="loading">Loading...</div>';
    }

    renderModules(articleIndex) {
        const modulesContainer = document.getElementById('modules-container');
        const sidebarContainer = document.getElementById('sidebar-category-widgets');
        
        if (!modulesContainer || !siteConfig.design.modules || siteConfig.design.modules.length === 0) {
            return '';
        }

        let mainModulesHtml = '';
        let sidebarModulesHtml = '';
        const modules = siteConfig.design.modules;
        
        // Randomly decide which modules go to sidebar vs main content
        modules.forEach((moduleType, index) => {
            let html = '';
            if (moduleType === 'featured-section') {
                html = this.renderFeaturedSection(articleIndex);
            } else if (moduleType === 'category-highlights') {
                html = this.renderCategoryHighlights();
            } else if (moduleType === 'trending-articles') {
                html = this.renderTrendingArticles(articleIndex);
            } else if (moduleType === 'about-widget') {
                html = this.renderAboutWidget();
            } else if (moduleType === 'newsletter-signup') {
                html = this.renderNewsletterSignup();
            } else if (moduleType === 'recent-comments') {
                html = this.renderRecentComments();
            } else if (moduleType === 'stats-widget') {
                html = this.renderStatsWidget(articleIndex);
            } else if (moduleType === 'social-links') {
                html = this.renderSocialLinks();
            } else if (moduleType === 'popular-tags') {
                html = this.renderPopularTags();
            }

            // Heuristic: some modules are better in sidebar, others in main
            const sidebarFriendly = ['about-widget', 'recent-comments', 'social-links', 'popular-tags', 'trending-articles'];
            
            if (sidebarFriendly.includes(moduleType) && Math.random() > 0.3) {
                sidebarModulesHtml += html;
            } else {
                mainModulesHtml += html;
            }
        });
        
        if (modulesContainer) modulesContainer.innerHTML = mainModulesHtml;
        if (sidebarContainer) sidebarContainer.innerHTML = sidebarModulesHtml;
    }

    renderFeaturedSection(articleIndex) {
        const featured = articleIndex.articles.slice(0, 4);
        return `
            <section class="featured-section">
                <h2>Featured Articles</h2>
                <div class="featured-grid">
                    ${featured.map(a => `
                        <div class="featured-card">
                            <h4><a href="article.html#/article/${a.slug}">${a.title}</a></h4>
                            <p>Discover more about ${a.title}</p>
                        </div>
                    `).join('')}
                </div>
            </section>
        `;
    }

    renderCategoryHighlights() {
        const cats = siteConfig.categories.slice(0, 4);
        return `
            <section class="category-highlights">
                ${cats.map(cat => `
                    <div class="category-highlight-card">
                        <h3>${getCategoryName(cat)}</h3>
                        <a href="index.html#/category/${cat}">Explore →</a>
                    </div>
                `).join('')}
            </section>
        `;
    }

    renderTrendingArticles(articleIndex) {
        const trending = articleIndex.articles.slice(0, 5);
        return `
            <section class="trending-articles">
                <h3>Trending Now</h3>
                <ul class="trending-list">
                    ${trending.map(a => `
                        <li class="trending-item">
                            <a href="article.html#/article/${a.slug}">${a.title}</a>
                        </li>
                    `).join('')}
                </ul>
            </section>
        `;
    }

    renderAboutWidget() {
        return `
            <aside class="about-widget">
                <h3>About Us</h3>
                <p>Welcome to ${siteConfig.design.site_title}, your source for quality content and articles. Explore, learn, and enjoy!</p>
            </aside>
        `;
    }

    renderNewsletterSignup() {
        return `
            <section class="newsletter-signup">
                <h3>Stay Updated</h3>
                <p>Get the latest articles delivered to your inbox</p>
                <form onsubmit="event.preventDefault(); alert('Thank you for subscribing!')">
                    <input type="email" placeholder="Your email address">
                    <button type="submit">Subscribe</button>
                </form>
            </section>
        `;
    }

    renderRecentComments() {
        const fakeComments = [
            { user: 'John', text: 'Great article, very helpful!' },
            { user: 'Sarah', text: 'Thanks for sharing this!' },
            { user: 'Mike', text: 'Excellent information!' }
        ];
        
        return `
            <div class="recent-comments sidebar-widget">
                <h3>Recent Comments</h3>
                ${fakeComments.map(c => `
                    <div class="comment-item">
                        <strong>${c.user}</strong>: ${c.text}
                    </div>
                `).join('')}
            </div>
        `;
    }

    renderStatsWidget(articleIndex) {
        return `
            <section class="stats-widget">
                <div class="stat-card">
                    <div class="stat-number">${articleIndex.articles.length}</div>
                    <div>Articles</div>
                </div>
                <div class="stat-card">
                    <div class="stat-number">${siteConfig.categories.length}</div>
                    <div>Categories</div>
                </div>
                <div class="stat-card">
                    <div class="stat-number">10K+</div>
                    <div>Readers</div>
                </div>
                <div class="stat-card">
                    <div class="stat-number">24/7</div>
                    <div>Updated</div>
                </div>
            </section>
        `;
    }

    renderSocialLinks() {
        const networks = [
            { name: 'Twitter', icon: '𝕏' },
            { name: 'Facebook', icon: 'f' },
            { name: 'Instagram', icon: '📷' },
            { name: 'LinkedIn', icon: 'in' }
        ];
        
        return `
            <div class="social-links sidebar-widget">
                <h3>Follow Us</h3>
                <div class="social-links">
                    ${networks.map(n => `
                        <a href="#" class="social-link">${n.icon}</a>
                    `).join('')}
                </div>
            </div>
        `;
    }

    renderPopularTags() {
        const tags = ['Tips', 'Guide', 'How-To', 'Beginner', 'Advanced', 'Best Practices', 'Trending'];
        return `
            <div class="sidebar-widget">
                <h3>Popular Tags</h3>
                <div class="popular-tags">
                    ${tags.map(tag => `
                        <a href="#" class="tag-item">${tag}</a>
                    `).join('')}
                </div>
            </div>
        `;
    }

    async renderHome() {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        const articleIndex = await this.dataService.loadArticleIndex();

        if (!articleIndex) {
            app.innerHTML = '<h1>Failed to load content</h1>';
            return;
        }

        // Render modules first!
        this.renderModules(articleIndex);

        // Render home banner
        if (bannerContainer) {
            bannerContainer.innerHTML = `
                <div class="home-banner">
                    <div class="container">
                        <h2>Welcome to ${siteConfig.design.site_title}</h2>
                        <p>Explore latest articles and get quality content</p>
                    </div>
                </div>`;
            bannerContainer.style.display = 'block';
        }

        let html = '';
        html += '<h1 class="page-title">All Articles</h1>';

        // Pagination logic
        const totalItems = articleIndex.articles.length;
        const totalPages = Math.ceil(totalItems / this.itemsPerPage);
        const startIndex = (this.currentPage - 1) * this.itemsPerPage;
        const endIndex = startIndex + this.itemsPerPage;
        const currentArticles = articleIndex.articles.slice(startIndex, endIndex);

        html += '<div class="article-grid">';

        for (let i = 0; i < currentArticles.length; i++) {
            const articleMeta = currentArticles[i];
            html += this.renderArticleCardSimple(articleMeta);

            // Insert AD-07 in-feed ad every 6 articles
            if ((i + 1) % 6 === 0) {
                html += this.renderAdSlot('AD-07', 'Sponsored Content');
            }
        }

        html += '</div>';

        // Add pagination controls
        if (totalPages > 1) {
            html += this.renderPaginationControls(totalPages, '#/page/');
        }

        app.innerHTML = html;
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
            this.renderFooterCategories();
        }, 100);
    }

    renderFooterCategories() {
        const container = document.getElementById('footer-categories-container');
        if (!container || !siteConfig.categories) return;
        
        container.innerHTML = siteConfig.categories.slice(0, 5).map(cat => `
            <a href="index.html#/category/${cat}">${getCategoryName(cat)}</a>
        `).join('');
    }

    async renderCategory(category) {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        const modulesContainer = document.getElementById('modules-container');

        // Hide home banner and modules on category page
        if (bannerContainer) {
            bannerContainer.innerHTML = '';
            bannerContainer.style.display = 'none';
        }
        if (modulesContainer) {
            modulesContainer.innerHTML = '';
        }

        const categoryArticles = await this.dataService.getArticlesByCategory(category);
        
        if (!categoryArticles) {
            app.innerHTML = '<h1>Failed to load content</h1>';
            return;
        }

        // Pagination logic
        const totalItems = categoryArticles.length;
        const totalPages = Math.ceil(totalItems / this.itemsPerPage);
        const startIndex = (this.currentPage - 1) * this.itemsPerPage;
        const endIndex = startIndex + this.itemsPerPage;
        const currentArticles = categoryArticles.slice(startIndex, endIndex);

        let html = `<h1 class="page-title">${getCategoryName(category)}</h1>`;
        html += '<div class="article-grid">';
        
        for (let i = 0; i < currentArticles.length; i++) {
            const articleMeta = currentArticles[i];
            html += this.renderArticleCardSimple(articleMeta);
            
            // Insert AD-07 in-feed ad every 6 articles
            if ((i + 1) % 6 === 0) {
                html += this.renderAdSlot('AD-07', 'Sponsored Content');
            }
        }
        
        html += '</div>';

        // Add pagination controls
        if (totalPages > 1) {
            html += this.renderPaginationControls(totalPages, `#/category/${category}/`);
        }
        
        app.innerHTML = html;
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
        }, 100);
    }

    async renderSearch(query) {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        const modulesContainer = document.getElementById('modules-container');

        if (bannerContainer) {
            bannerContainer.innerHTML = '';
            bannerContainer.style.display = 'none';
        }
        if (modulesContainer) {
            modulesContainer.innerHTML = '';
        }

        const articleIndex = await this.dataService.loadArticleIndex();
        if (!articleIndex) return;

        const results = articleIndex.articles.filter(a => 
            a.title.toLowerCase().includes(query.toLowerCase()) || 
            (a.content && a.content.toLowerCase().includes(query.toLowerCase()))
        );

        let html = `<h1 class="page-title">Search Results for: "${query}"</h1>`;
        
        if (results.length === 0) {
            html += '<p class="no-results">No articles found matching your search.</p>';
        } else {
            html += `<p class="search-meta">Found ${results.length} articles</p>`;
            html += '<div class="article-grid">';
            results.forEach(article => {
                html += this.renderArticleCardSimple(article);
            });
            html += '</div>';
        }
        
        app.innerHTML = html;

        // Show search ad if exists
        const searchAd = document.getElementById('search-ad-container');
        if (searchAd) {
            searchAd.style.display = 'block';
            searchAd.innerHTML = this.renderAdSlot('AD-11', 'Search Page Ad');
        }
    }

    renderPaginationControls(totalPages, baseUrl) {
        let html = '<div class="pagination">';
        
        if (this.currentPage > 1) {
            html += `<a href="${baseUrl}${this.currentPage - 1}" class="page-btn">Previous</a>`;
        }
        
        for (let i = 1; i <= totalPages; i++) {
            const isActive = i === this.currentPage;
            // Display max 10 page buttons to prevent overflow
            if (i === 1 || i === totalPages || (i >= this.currentPage - 2 && i <= this.currentPage + 2)) {
                html += `<a href="${baseUrl}${i}" class="page-btn ${isActive ? 'active' : ''}">${i}</a>`;
            } else if (i === this.currentPage - 3 || i === this.currentPage + 3) {
                html += `<span>...</span>`;
            }
        }
        
        if (this.currentPage < totalPages) {
            html += `<a href="${baseUrl}${this.currentPage + 1}" class="page-btn">Next</a>`;
        }
        
        html += '</div>';
        return html;
    }

    async renderArticle(slug) {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        const modulesContainer = document.getElementById('modules-container');

        // Hide home banner and modules on article page
        if (bannerContainer) {
            bannerContainer.innerHTML = '';
            bannerContainer.style.display = 'none';
        }
        if (modulesContainer) {
            modulesContainer.innerHTML = '';
        }

        const article = await this.dataService.loadArticleBySlug(slug);
        
        if (!article) {
            app.innerHTML = '<h1>Article not found</h1>';
            return;
        }
        
        // Render article with ads
        app.innerHTML = this.renderArticleWithAds(article);
        
        // Update page title
        document.title = article.title + ' - ' + siteConfig.siteId;
        if (article.seo && article.seo.title_tag) {
            document.title = article.seo.title_tag;
        }
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
        }, 100);
    }

    renderArticleWithAds(article) {
        let html = '<div class="article-full">';
        
        html += '<div style="margin-bottom: 1rem;">';
        html += `<a href="index.html#/">Home</a> | `;
        html += `<a href="index.html#/category/${article.category}">${getCategoryName(article.category)}</a>`;
        html += '</div>';
        
        html += `<span class="category-tag">${getCategoryName(article.category)}</span>`;
        html += `<h1>${article.title}</h1>`;
        html += `<p class="article-meta">${new Date(article.created_at).toLocaleDateString()}`;
        
        if (article.geo) {
            html += ` | Location: ${article.geo.city}, ${article.geo.country}`;
        }
        html += `</p>`;
        
        // Add article image
        if (article.image && article.image.url) {
            html += `<img src="${article.image.url}" alt="${article.image.alt || article.title}" style="width: 100%; max-height: 400px; object-fit: cover; margin: 1rem 0; border-radius: 8px;">`;
        }
        
        // Split article content and insert ads
        const paragraphs = article.content.split('</p>').filter(p => p.trim());
        
        // Insert AD-04 after first paragraph
        if (paragraphs.length > 0) {
            html += paragraphs[0] + '</p>';
            html += this.renderAdSlot('AD-04', 'In-Article 1');
        }
        
        // Insert AD-05 at 50% position
        const middleIndex = Math.floor(paragraphs.length / 2);
        for (let i = 1; i < paragraphs.length; i++) {
            html += paragraphs[i] + '</p>';
            
            if (i === middleIndex && middleIndex > 0) {
                html += this.renderAdSlot('AD-05', 'In-Article 2');
            }
        }
        
        // Insert AD-06 at end of article
        html += this.renderAdSlot('AD-06', 'In-Article 3');
        
        html += '</div>';
        return html;
    }

    renderAdSlot(slotId, label) {
        return `
            <div class="ad-slot" 
                 data-ad-container="true" 
                 data-ad-id="${slotId}" 
                 data-ad-position="${slotId.toLowerCase()}"
                 data-ad-networks="adsense,adsterra,gam"
                 data-ad-status="pending"
                 style="margin: 2rem 0; min-height: 200px; display: none;">
                <div class="ad-skeleton">
                    <div class="ad-label">${slotId} - ${label}</div>
                </div>
                <div class="ad-content" data-ad-network="adsense"></div>
                <div class="ad-content" data-ad-network="adsterra"></div>
                <div class="ad-content" data-ad-network="gam"></div>
            </div>
        `;
    }

    renderArticleCardSimple(articleMeta) {
        const style = siteConfig.design.article_card_style || 'card';
        
        // Base structure
        let html = `<div class="article-card card-style-${style}" style="cursor: pointer;" onclick="window.location.href='article.html#/article/${articleMeta.slug}'">`;
        
        // Image part - Always show image as per user requirement
        if (articleMeta.image && articleMeta.image.url) {
            html += `<div class="article-card-image">`;
            html += `<img src="${articleMeta.image.url}" alt="${articleMeta.image.alt || articleMeta.title}" loading="lazy">`;
            html += '</div>';
        }
        
        // Content part
        html += '<div class="article-card-content">';
        html += `<span class="category-tag">${getCategoryName(articleMeta.category)}</span>`;
        html += `<h3><a href="article.html#/article/${articleMeta.slug}">${articleMeta.title}</a></h3>`;
        
        if (style !== 'minimal' && style !== 'grid') {
            html += `<p>Read more about ${articleMeta.title}...</p>`;
        }
        
        html += '</div></div>';
        
        return html;
    }
}

document.addEventListener('DOMContentLoaded', () => {
    new App();
});